mapper.select:
select rl.ledger_id, rl.order_id, om.order_no, rl.contest_id, rl.rebate_amount, rl.direction, rl.status, rl.settlement_id, rl.accrual_time, rl.create_time from jst_rebate_ledger rl left join jst_order_main om on om.order_id = rl.order_id and om.del_flag = '0' where rl.channel_id = #{channelId} and rl.del_flag = '0'
and rl.status = #{status}
order by rl.create_time desc, rl.ledger_id desc

select * from jst_rebate_ledger where ledger_id in
#{ledgerId}
and del_flag = '0' order by ledger_id asc for update

mapper.update:
update jst_rebate_ledger set status = 'in_review', settlement_id = #{settlementId}, update_by = #{updateBy}, update_time = #{updateTime} where channel_id = #{channelId} and ledger_id in
#{ledgerId}
and status = 'withdrawable' and direction = 'positive' and del_flag = '0'

update jst_rebate_ledger
set status = 'withdrawable',
    settlement_id = null,
    update_by = #{updateBy},
    update_time = #{updateTime}
where channel_id = #{channelId}
  and settlement_id = #{settlementId}
  and status = 'in_review'
  and direction = 'positive'
  and del_flag = '0'

update jst_rebate_ledger
set settlement_id = #{settlementId},
    update_by = #{updateBy},
    update_time = #{updateTime}
where channel_id = #{channelId}
  and ledger_id in

    #{ledgerId}

  and direction = 'negative'
  and settlement_id is null
  and del_flag = '0'

update jst_rebate_ledger
set status = 'paid',
    update_by = #{updateBy},
    update_time = #{updateTime}
where channel_id = #{channelId}
  and settlement_id = #{settlementId}
  and status = 'in_review'
  and direction = 'positive'
  and del_flag = '0'
